class WebSocketServer:
    def __init__(self, port=80):
        self.port = port
        self.server_socket = None
        self.clients = []
        self.running = False
        
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind(('0.0.0.0', self.port))
        self.server_socket.listen(5)
        self.server_socket.setblocking(False)
        self.running = True
        print(f"WebSocket server started on port {self.port}")
        
    def stop(self):
        self.running = False
        for client in self.clients:
            try:
                client['socket'].close()
            except:
                pass
        self.clients.clear()
        if self.server_socket:
            self.server_socket.close()
        print("WebSocket server stopped")
        
    def _make_websocket_key(self, key):
        magic_string = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
        hash_obj = uhashlib.sha1(key.encode() + magic_string.encode())
        accept_key = ubinascii.b2a_base64(hash_obj.digest()).strip()
        return accept_key.decode()
        
    def _parse_http_request(self, request):
        lines = request.split(b'\r\n')
        headers = {}
        for line in lines[1:]:
            if b': ' in line:
                key, value = line.split(b': ', 1)
                headers[key.decode().lower()] = value.decode()
        return headers
        
    def _send_websocket_handshake(self, client_socket, headers):
        if 'sec-websocket-key' not in headers:
            return False
            
        accept_key = self._make_websocket_key(headers['sec-websocket-key'])
        
        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            f"Sec-WebSocket-Accept: {accept_key}\r\n"
            "\r\n"
        )
        
        try:
            client_socket.send(response.encode())
            return True
        except:
            return False
            
    def _decode_websocket_frame(self, data):
        if len(data) < 2:
            return None
            
        fin = (data[0] & 0x80) >> 7
        opcode = data[0] & 0x0F
        masked = (data[1] & 0x80) >> 7
        payload_length = data[1] & 0x7F
        
        offset = 2
        
        if payload_length == 126:
            if len(data) < 4:
                return None
            payload_length = int.from_bytes(data[2:4], 'big')
            offset = 4
        elif payload_length == 127:
            if len(data) < 10:
                return None
            payload_length = int.from_bytes(data[2:10], 'big')
            offset = 10
            
        if masked:
            if len(data) < offset + 4:
                return None
            masking_key = data[offset:offset+4]
            offset += 4
        else:
            masking_key = None
            
        if len(data) < offset + payload_length:
            return None
            
        payload = bytearray(data[offset:offset+payload_length])
        
        if masked and masking_key:
            for i in range(len(payload)):
                payload[i] ^= masking_key[i % 4]
                
        return {
            'fin': fin,
            'opcode': opcode,
            'payload': bytes(payload)
        }
        
    def _encode_websocket_frame(self, payload, opcode=0x01):
        frame = bytearray()
        frame.append(0x80 | opcode)
        
        payload_length = len(payload)
        
        if payload_length < 126:
            frame.append(payload_length)
        elif payload_length < 65536:
            frame.append(126)
            frame.extend(payload_length.to_bytes(2, 'big'))
        else:
            frame.append(127)
            frame.extend(payload_length.to_bytes(8, 'big'))
            
        if isinstance(payload, str):
            frame.extend(payload.encode())
        else:
            frame.extend(payload)
            
        return bytes(frame)
        
    def send_message(self, client, message):
        if isinstance(message, dict):
            message = json.dumps(message)
        frame = self._encode_websocket_frame(message)
        try:
            client['socket'].send(frame)
            return True
        except:
            return False
            
    def broadcast(self, message):
        if isinstance(message, dict):
            message = json.dumps(message)
        frame = self._encode_websocket_frame(message)
        
        dead_clients = []
        for client in self.clients:
            try:
                client['socket'].send(frame)
            except:
                dead_clients.append(client)
                
        for client in dead_clients:
            self._remove_client(client)
            
    def _remove_client(self, client):
        try:
            client['socket'].close()
        except:
            pass
        if client in self.clients:
            self.clients.remove(client)
            print(f"Client disconnected. Total clients: {len(self.clients)}")
            
    def _accept_client(self):
        try:
            client_socket, addr = self.server_socket.accept()
            client_socket.setblocking(False)
            
            data = b''
            timeout = time.time() + 2
            while time.time() < timeout:
                try:
                    chunk = client_socket.recv(1024)
                    if chunk:
                        data += chunk
                        if b'\r\n\r\n' in data:
                            break
                except OSError:
                    time.sleep(0.01)
                    
            if not data:
                client_socket.close()
                return
                
            headers = self._parse_http_request(data)
            
            if 'upgrade' in headers and headers['upgrade'].lower() == 'websocket':
                if self._send_websocket_handshake(client_socket, headers):
                    client = {
                        'socket': client_socket,
                        'address': addr,
                        'buffer': b''
                    }
                    self.clients.append(client)
                    print(f"WebSocket client connected from {addr}. Total clients: {len(self.clients)}")
                else:
                    client_socket.close()
            else:
                client_socket.close()
                
        except OSError:
            pass
            
    def _handle_client_data(self, client):
        try:
            data = client['socket'].recv(1024)
            if not data:
                self._remove_client(client)
                return None
                
            client['buffer'] += data
            
            frame = self._decode_websocket_frame(client['buffer'])
            if frame:
                client['buffer'] = b''
                
                if frame['opcode'] == 0x08:
                    self._remove_client(client)
                    return None
                elif frame['opcode'] == 0x09:
                    pong_frame = self._encode_websocket_frame(frame['payload'], opcode=0x0A)
                    client['socket'].send(pong_frame)
                    return None
                elif frame['opcode'] == 0x01:
                    return frame['payload'].decode()
                    
        except OSError:
            pass
        except Exception as e:
            print(f"Error handling client data: {e}")
            self._remove_client(client)
            
        return None
        
    def poll(self):
        if not self.running:
            return []
            
        self._accept_client()
        
        messages = []
        dead_clients = []
        
        for client in self.clients:
            message = self._handle_client_data(client)
            if message:
                messages.append({
                    'client': client,
                    'message': message
                })
                
        return messages


class IoTDevice:
    def __init__(self):
        self.ws_server = WebSocketServer(port=80)
        self.led = machine.Pin(2, machine.Pin.OUT)
        self.state = {
            'led': False,
            'device_name': 'ESP32-IoT'
        }
        
    def connect_wifi(self, ssid, password):
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)
        
        if not wlan.isconnected():
            print(f'Connecting to WiFi {ssid}...')
            wlan.connect(ssid, password)
            
            timeout = 10
            while not wlan.isconnected() and timeout > 0:
                time.sleep(1)
                timeout -= 1
                
        if wlan.isconnected():
            print('WiFi connected!')
            print('IP address:', wlan.ifconfig()[0])
            return True
        else:
            print('Failed to connect to WiFi')
            return False
            
    def handle_command(self, command_str, client):
        try:
            command = json.loads(command_str)
            action = command.get('action')
            
            response = {'status': 'error', 'message': 'Unknown action'}
            
            if action == 'turn_on':
                self.led.value(1)
                self.state['led'] = True
                response = {'status': 'success', 'action': 'turn_on', 'state': self.state}
                
            elif action == 'turn_off':
                self.led.value(0)
                self.state['led'] = False
                response = {'status': 'success', 'action': 'turn_off', 'state': self.state}
                
            elif action == 'toggle':
                self.state['led'] = not self.state['led']
                self.led.value(1 if self.state['led'] else 0)
                response = {'status': 'success', 'action': 'toggle', 'state': self.state}
                
            elif action == 'get_state':
                response = {'status': 'success', 'state': self.state}
                
            elif action == 'set_name':
                name = command.get('name', 'ESP32-IoT')
                self.state['device_name'] = name
                response = {'status': 'success', 'action': 'set_name', 'state': self.state}
                
            self.ws_server.send_message(client, response)
            
        except Exception as e:
            error_response = {'status': 'error', 'message': str(e)}
            self.ws_server.send_message(client, error_response)
            
    def run(self):
        self.ws_server.start()
        print("IoT Device ready. Send JSON commands via WebSocket.")
        
        try:
            while True:
                messages = self.ws_server.poll()
                
                for msg in messages:
                    print(f"Received: {msg['message']}")
                    self.handle_command(msg['message'], msg['client'])
                    
                time.sleep(0.01)
                
        except KeyboardInterrupt:
            print("\nStopping server...")
            self.ws_server.stop()


